SELECT season, AVG(temp) AS avg_temp, AVG(atemp) AS avg_atemp
FROM daily_usage
GROUP BY season;

SELECT hour, SUM(total_count) AS hourly_total_rentals
FROM hourly_usage
GROUP BY hour;

SELECT AVG(total_count) AS average_total_count
FROM daily_usage
WHERE holiday = 0;

SELECT DATE(rental_start_date_time) AS rental_date, COUNT(rental_id) AS total_bike_rentals
FROM rentals
GROUP BY DATE(rental_start_date_time);

SELECT station_name, latitude, longitude, capacity
FROM station_info
WHERE capacity > 30;

SELECT COUNT(*) AS count_of_large_stations
FROM station_info
WHERE capacity > 50;

SELECT r.rental_start_date_time, e.event_name
FROM rentals r
JOIN events e ON strftime('%Y-%m-%d', r.rental_start_date_time) = strftime('%Y-%m-%d', e.event_date);
